import java.util.*;
public class HMBasics {
    public static void main(String[] a) {
        Map<String,Integer> m = new HashMap<>();
        m.put("A", 1); m.put("B", 2); m.put("C", 3);
        System.out.println(m.get("B"));                // 2
        System.out.println(m.getOrDefault("D", -1));  // -1
        System.out.println(m.containsKey("A"));        // true
        m.put("A", 10);
        System.out.println(m.get("A"));                // 10 (overwrite)
        System.out.println(m.size());                  // 3
        System.out.println("O(1) avg: put/get/containsKey/size");
    }
}

import java.util.*;
public class FreqCount {
    public static void main(String[] a) {
        int[] nums = {1, 2, 2, 3, 3, 3, 4};
        Map<Integer,Integer> freq = new HashMap<>();
        for (int n : nums) freq.merge(n, 1, Integer::sum);
        System.out.println(freq.get(1));  // 1
        System.out.println(freq.get(2));  // 2
        System.out.println(freq.get(3));  // 3
        System.out.println("merge(k, 1, Integer::sum): elegant frequency count");
        System.out.println("Alternative: getOrDefault(k,0)+1");
    }
}

import java.util.*;
public class TwoSum {
    public static int[] twoSum(int[] nums, int target) {
        Map<Integer,Integer> map = new HashMap<>(); // val → index
        for (int i = 0; i < nums.length; i++) {
            int complement = target - nums[i];
            if (map.containsKey(complement)) return new int[]{map.get(complement), i};
            map.put(nums[i], i);
        }
        return new int[]{};
    }
    public static void main(String[] a) {
        System.out.println(Arrays.toString(twoSum(new int[]{2,7,11,15}, 9)));  // [0,1]
        System.out.println(Arrays.toString(twoSum(new int[]{3,2,4}, 6)));      // [1,2]
        System.out.println(Arrays.toString(twoSum(new int[]{3,3}, 6)));        // [0,1]
        System.out.println("O(n) — one pass, complement lookup");
    }
}

import java.util.*;
public class SubarraySumK {
    public static int subarraySum(int[] nums, int k) {
        Map<Integer,Integer> prefixCount = new HashMap<>();
        prefixCount.put(0, 1); // empty prefix
        int sum = 0, count = 0;
        for (int n : nums) {
            sum += n;
            count += prefixCount.getOrDefault(sum - k, 0);
            prefixCount.merge(sum, 1, Integer::sum);
        }
        return count;
    }
    public static void main(String[] a) {
        System.out.println(subarraySum(new int[]{1,1,1}, 2));    // 2
        System.out.println(subarraySum(new int[]{1,2,3}, 3));    // 2
        System.out.println(subarraySum(new int[]{-1,-1,1}, 0)); // 1
        System.out.println("O(n) — prefix sum + HashMap. prefixCount.put(0,1) handles subarrays from index 0");
    }
}

import java.util.*;
public class HMInternals {
    public static void main(String[] a) {
        // Default: capacity=16, loadFactor=0.75
        // Resize when size > capacity * loadFactor = 16 * 0.75 = 12
        // Resize: capacity doubles (16 → 32), rehash all keys
        // Pre-size: avoid resizing when n is known
        Map<String,Integer> small = new HashMap<>(4, 0.75f);
        Map<String,Integer> large = new HashMap<>(1024); // pre-sized for 1024 entries
        System.out.println("Default capacity: 16, load factor: 0.75");
        System.out.println("Resize threshold: 16 * 0.75 = 12 entries");
        System.out.println("After resize: capacity=32, all keys rehashed");
        System.out.println("Pre-size: new HashMap<>(n*4/3+1) to avoid resizes");
        System.out.println("O(1) avg because: good hash distributes evenly across buckets");
    }
}

import java.util.*;
public class CharFreq {
    public static int firstUniqChar(String s) {
        int[] freq = new int[26];
        for (char c : s.toCharArray()) freq[c-'a']++;
        for (int i = 0; i < s.length(); i++)
            if (freq[s.charAt(i)-'a'] == 1) return i;
        return -1;
    }
    public static void main(String[] a) {
        System.out.println(firstUniqChar("leetcode"));     // 0 ('l')
        System.out.println(firstUniqChar("loveleetcode")); // 2 ('v')
        System.out.println(firstUniqChar("aabb"));         // -1
        System.out.println("int[26] preferred over HashMap for lowercase alpha: O(1) space");
    }
}

import java.util.*;
public class ContiguousArray {
    public static int findMaxLength(int[] nums) {
        Map<Integer,Integer> map = new HashMap<>();
        map.put(0, -1); // balance 0 seen at index -1
        int balance = 0, maxLen = 0;
        for (int i = 0; i < nums.length; i++) {
            balance += nums[i] == 1 ? 1 : -1;
            if (map.containsKey(balance)) maxLen = Math.max(maxLen, i - map.get(balance));
            else map.put(balance, i);
        }
        return maxLen;
    }
    public static void main(String[] a) {
        System.out.println(findMaxLength(new int[]{0,1}));         // 2
        System.out.println(findMaxLength(new int[]{0,1,0}));       // 2
        System.out.println(findMaxLength(new int[]{0,0,1,0,0,0,1,1})); // 6
        System.out.println("O(n) — balance (0→-1, 1→+1), same balance at i and j means equal 0s and 1s in (j,i]");
    }
}

import java.util.*;
public class MapTypes {
    public static void main(String[] a) {
        // HashMap: O(1) ops, no order guarantee
        Map<Integer,String> hm = new HashMap<>();
        hm.put(3,"c"); hm.put(1,"a"); hm.put(2,"b");
        System.out.println("HashMap keys (random order): " + hm.keySet());

        // TreeMap: O(log n) ops, sorted by key
        Map<Integer,String> tm = new TreeMap<>(hm);
        System.out.println("TreeMap keys (sorted): " + tm.keySet()); // [1,2,3]

        // LinkedHashMap: O(1) ops, insertion order
        Map<Integer,String> lhm = new LinkedHashMap<>(hm);
        System.out.println("LinkedHashMap keys (insertion): " + lhm.keySet()); // [3,1,2]

        System.out.println("HashMap O(1), TreeMap O(log n), LinkedHashMap O(1)+order");
    }
}

import java.util.*;
public class LongestConsec {
    public static int longestConsecutive(int[] nums) {
        Set<Integer> set = new HashSet<>();
        for (int n : nums) set.add(n);
        int best = 0;
        for (int n : set) {
            if (!set.contains(n - 1)) { // start of a sequence
                int curr = n, len = 1;
                while (set.contains(curr + 1)) { curr++; len++; }
                best = Math.max(best, len);
            }
        }
        return best;
    }
    public static void main(String[] a) {
        System.out.println(longestConsecutive(new int[]{100,4,200,1,3,2})); // 4
        System.out.println(longestConsecutive(new int[]{0,3,7,2,5,8,4,6,0,1})); // 9
        System.out.println("O(n) — HashSet for O(1) lookup. Only start sequence when n-1 not in set");
    }
}

import java.util.*;
public class FourSumII {
    public static int fourSumCount(int[] a, int[] b, int[] c, int[] d) {
        Map<Integer,Integer> abSum = new HashMap<>();
        for (int x : a) for (int y : b) abSum.merge(x+y, 1, Integer::sum);
        int count = 0;
        for (int x : c) for (int y : d) count += abSum.getOrDefault(-(x+y), 0);
        return count;
    }
    public static void main(String[] a2) {
        System.out.println(fourSumCount(new int[]{1,2},new int[]{-2,-1},new int[]{-1,2},new int[]{0,2})); // 2
        System.out.println(fourSumCount(new int[]{0},new int[]{0},new int[]{0},new int[]{0})); // 1
        System.out.println("O(n²) — split into two pairs, HashMap for complement lookup");
    }
}

import java.util.*;
public class RandomPickIdx {
    static class Solution {
        Map<Integer,List<Integer>> map = new HashMap<>(); Random rnd = new Random();
        Solution(int[] nums) { for(int i=0;i<nums.length;i++) map.computeIfAbsent(nums[i],k->new ArrayList<>()).add(i); }
        int pick(int target) { List<Integer> idxs=map.get(target); return idxs.get(rnd.nextInt(idxs.size())); }
    }
    public static void main(String[] a) {
        Solution s = new Solution(new int[]{1,2,3,3,3});
        int p = s.pick(3); System.out.println(p>=2 && p<=4); // true (index 2,3, or 4)
        System.out.println(s.pick(1) == 0); // true (only at index 0)
        System.out.println("O(n) build, O(1) pick — precompute index lists");
    }
}

import java.util.*;
public class HMSynth {
    static int[] twoSum(int[] n, int t){Map<Integer,Integer> m=new HashMap<>();for(int i=0;i<n.length;i++){int c=t-n[i];if(m.containsKey(c))return new int[]{m.get(c),i};m.put(n[i],i);}return new int[]{};}
    static int subarrayK(int[] n, int k){Map<Integer,Integer> m=new HashMap<>();m.put(0,1);int s=0,c=0;for(int x:n){s+=x;c+=m.getOrDefault(s-k,0);m.merge(s,1,Integer::sum);}return c;}
    static int longConsec(int[] n){Set<Integer> s=new HashSet<>();for(int x:n)s.add(x);int b=0;for(int x:s){if(!s.contains(x-1)){int c=x,l=1;while(s.contains(c+1)){c++;l++;}b=Math.max(b,l);}}return b;}
    public static void main(String[] a){
        System.out.println(Arrays.toString(twoSum(new int[]{2,7,11,15},9)));
        System.out.println(subarrayK(new int[]{1,1,1},2));
        System.out.println(longConsec(new int[]{100,4,200,1,3,2}));
        boolean ok=Arrays.equals(twoSum(new int[]{2,7,11,15},9),new int[]{0,1})&&subarrayK(new int[]{1,1,1},2)==2&&longConsec(new int[]{100,4,200,1,3,2})==4;
        System.out.println("All pass: "+ok);
    }
}

